import GelirEkleme from "./GelirGider/GelirEkleme"; // 💡 Yeni import

// ...
<Routes>
    <Route
        path="/"
        element={
            isAuthenticated ? (
                <Layout>
                    <AnaSayfa />
                </Layout>
            ) : (
                <Login onLoginSuccess={() => setIsAuthenticated(true)} />
            )
        }
    />
    <Route
        path="/dashboard"
        element={
            isAuthenticated ? (
                <Layout>
                    <Dashboard />
                </Layout>
            ) : (
                <Navigate to="/" />
            )
        }
    />
    {/* 💡 Yeni rota */}
    <Route
        path="/gelir-ekleme"
        element={
            isAuthenticated ? (
                <Layout>
                    <GelirEkleme />
                </Layout>
            ) : (
                <Navigate to="/" />
            )
        }
    />
</Routes>
